            <form onSubmit={handleRefundSubmit} className="space-y-4">
                <div className="bg-red-50 dark:bg-red-900/20 p-4 rounded-xl border border-red-100 dark:border-red-900/50">
                    <div className="flex items-center gap-3 mb-2">
                        <RefreshCcw className="text-red-600" size={20}/>
                        <p className="text-sm text-red-800 dark:text-red-300 font-bold">{t('billing_modal_refund_subtitle', {billNumber: refundingBill.billNumber})}</p>
                    </div>
                    <div className="flex justify-between text-xs text-red-600 dark:text-red-400">
                        <span>{t('billing_modal_refund_total_paid')}: ${refundingBill.paidAmount}</span>
                        <span>{t('billing_modal_refund_max')}: ${refundingBill.paidAmount}</span>
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <Input 
                        label={t('billing_modal_refund_amount')} 
                        type="number" 
                        max={refundingBill.paidAmount}
                        value={refundForm.amount}
                        onChange={e => setRefundForm({...refundForm, amount: e.target.value})}
                        required
                    />
                    <Select 
                        label={t('billing_modal_refund_method')}
                        value={refundForm.method}
                        onChange={e => setRefundForm({...refundForm, method: e.target.value})}
                    >
                        <option value="Cash">Cash</option>
                        <option value="Bank Transfer">Bank Transfer</option>
                        <option value="Credit Card Reversal">Credit Card Reversal</option>
                        <option value="Check">Check</option>
                    </Select>
                </div>

                <Select 
                    label={t('billing_modal_refund_reason')} 
                    value={refundForm.reason}
                    onChange={e => setRefundForm({...refundForm, reason: e.target.value})}
                    required
                >
                    <option value="Service Cancelled">{t('billing_modal_refund_reason_service')}</option>
                    <option value="Overcharged">{t('billing_modal_refund_reason_overcharged')}</option>
                    <option value="Duplicate Payment">{t('billing_modal_refund_reason_duplicate')}</option>
                    <option value="Customer Satisfaction">{t('billing_modal_refund_reason_satisfaction')}</option>
                    <option value="Other">{t('billing_modal_refund_reason_other')}</option>
                </Select>

                {refundForm.reason === 'Other' && (
                    <Textarea 
                        label={t('billing_modal_refund_custom_reason')} 
                        value={refundForm.customReason}
                        onChange={e => setRefundForm({...refundForm, customReason: e.target.value})}
                        required
                        rows={2}
                    />
                )}

                <div className="flex justify-end pt-4 gap-2">
                    <Button type="button" variant="secondary" onClick={() => setIsRefundModalOpen(false)}>{t('cancel')}</Button>
                    <Button type="submit" variant="danger" disabled={isProcessing}>
                        {isProcessing ? t('processing') : t('billing_modal_refund_confirm')}
                    </Button>
                </div>
            </form>
        )}
      </Modal>

      {/* Expense Modal */}
      <Modal isOpen={isExpenseModalOpen} onClose={() => setIsExpenseModalOpen(false)} title={t('billing_modal_expense_title')}>
          <form onSubmit={handleExpenseSubmit} className="space-y-4">
              <Select label={t('billing_modal_expense_category')} value={expenseForm.category} onChange={e => setExpenseForm({...expenseForm, category: e.target.value})}>
                  <option value="General">{t('billing_modal_expense_cat_general')}</option>
                  <option value="Supplies">{t('billing_modal_expense_cat_supplies')}</option>
                  <option value="Maintenance">{t('billing_modal_expense_cat_maintenance')}</option>
                  <option value="Utilities">{t('billing_modal_expense_cat_utilities')}</option>
                  <option value="Salary">{t('billing_modal_expense_cat_salary')}</option>
                  <option value="Equipment">{t('billing_modal_expense_cat_equipment')}</option>
              </Select>
              <Input label={t('billing_modal_expense_amount')} type="number" required value={expenseForm.amount} onChange={e => setExpenseForm({...expenseForm, amount: e.target.value})} />
              <div className="grid grid-cols-2 gap-4">
                  <Select label={t('billing_modal_expense_method')} value={expenseForm.method} onChange={e => setExpenseForm({...expenseForm, method: e.target.value})}>
                      <option value="Cash">Cash</option>
                      <option value="Bank Transfer">Bank Transfer</option>
                      <option value="Check">Check</option>
                  </Select>
                  <Input label={t('date')} type="date" required value={expenseForm.date} onChange={e => setExpenseForm({...expenseForm, date: e.target.value})} />
              </div>
              <Textarea label={t('billing_modal_expense_description')} required rows={3} value={expenseForm.description} onChange={e => setExpenseForm({...expenseForm, description: e.target.value})} />
              <div className="flex justify-end pt-4 gap-3">
                  <Button type="button" variant="secondary" onClick={() => setIsExpenseModalOpen(false)}>{t('cancel')}</Button>
                  <Button type="submit" disabled={isProcessing}>
                      {isProcessing ? t('processing') : t('billing_modal_expense_save')}
                  </Button>
              </div>
          </form>
      </Modal>

      <Modal isOpen={!!selectedBill} onClose={() => setSelectedBill(null)} title={t('billing_modal_preview_title')}>
        {selectedBill && (
          <div>
            <InvoiceView bill={selectedBill} />
            <div className="mt-6 flex justify-end gap-3">
              <Button variant="secondary" onClick={() => setSelectedBill(null)}>{t('close')}</Button>
              <Button icon={Printer}>{t('billing_modal_preview_print_button')}</Button>
            </div>
          </div>
        )}
      </Modal>

      {/* Confirmation Dialog for Service Cancellation */}
      <ConfirmationDialog 
        isOpen={confirmState.isOpen}
        onClose={() => setConfirmState({ ...confirmState, isOpen: false })}
        onConfirm={confirmState.action}
        title={confirmState.title}
        message={confirmState.message}
        type={confirmState.type}
      />

    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Card, Button, Modal, Badge } from '../components/UI';
import { 
  Search, Calendar, Filter, Database, FileText, User, Users, 
  DollarSign, Bed, Activity, Download, Eye, ChevronLeft, ChevronRight, ChevronsLeft, ChevronsRight,
  FileSpreadsheet, Printer, ChevronDown
} from 'lucide-react';
import { api } from '../services/api';
import { useTranslation } from '../context/TranslationContext';

// Unified Record Interface
interface SystemRecord {
  id: string; // Unique combination key
  originalId: number;
  type: 'Patient' | 'Appointment' | 'Bill' | 'Admission';
  reference: string;
  date: string;
  primaryEntity: string;
  associateEntity?: string;
  status: string;
  value?: number;
  details?: any;
}

export const Records = () => {
  const [loading, setLoading] = useState(true);
  const [records, setRecords] = useState<SystemRecord[]>([]);
  const { t } = useTranslation();

  // Filters
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState('All');
  const [dateRange, setDateRange] = useState({ start: '', end: '' });

  // Modal
  const [selectedRecord, setSelectedRecord] = useState<SystemRecord | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Pagination
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(10);

  // Export Menu State
  const [showExportMenu, setShowExportMenu] = useState(false);
  const exportMenuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const [pts, apts, bills, admissions] = await Promise.all([
          api.getPatients(),
          api.getAppointments(),
          api.getBills(),
          api.getActiveAdmissions()
        ]);

        const allRecords: SystemRecord[] = [];

        // Normalize Patients
        (Array.isArray(pts) ? pts : []).forEach((p: any) => {
          if (p && p.id && p.createdAt) {
            allRecords.push({
              id: `pat-${p.id}`,
              originalId: p.id,
              type: 'Patient',
              reference: p.patientId,
              date: p.createdAt,
              primaryEntity: p.fullName,
              status: p.type,
              details: p
            });
          }
        });

        // Normalize Appointments
        (Array.isArray(apts) ? apts : []).forEach((a: any) => {
          if (a && a.id && a.datetime) {
            allRecords.push({
              id: `apt-${a.id}`,
              originalId: a.id,
              type: 'Appointment',
              reference: a.appointmentNumber,
              date: a.datetime,
              primaryEntity: a.patientName,
              associateEntity: a.staffName,
              status: a.status,
              details: a
            });
          }
        });

        // Normalize Bills
        (Array.isArray(bills) ? bills : []).forEach((b: any) => {
          if (b && b.id && b.date) {
            allRecords.push({
              id: `bill-${b.id}`,
              originalId: b.id,
              type: 'Bill',
              reference: b.billNumber,
              date: b.date,
              primaryEntity: b.patientName,
              status: b.status,
              value: b.totalAmount,
              details: b
            });
          }
        });

        // Normalize Admissions
        (Array.isArray(admissions) ? admissions : []).forEach((ad: any) => {
          const entryDate = ad.entry_date || ad.entryDate;
          if (ad && ad.id && entryDate) {
            allRecords.push({
              id: `adm-${ad.id}`,
              originalId: ad.id,
              type: 'Admission',
              reference: `BED-${ad.roomNumber}`,
              date: entryDate,
              primaryEntity: ad.patientName,
              associateEntity: ad.doctorName,
              status: ad.status,
              details: ad
            });
          }
        });

        // Sort by date descending
        setRecords(allRecords.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));

      } catch (e) {
        console.error("Failed to fetch records:", e);
      } finally {
        setLoading(false);
      }
    };
    fetchData();

    // Close export menu on outside click
    const handleClickOutside = (event: MouseEvent) => {
      if (exportMenuRef.current && !exportMenuRef.current.contains(event.target as Node)) {
        setShowExportMenu(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // --- Filtering Logic ---
  const filteredRecords = useMemo(() => {
    return records.filter(r => {
      const matchesSearch = 
        r.reference.toLowerCase().includes(searchTerm.toLowerCase()) || 
        r.primaryEntity.toLowerCase().includes(searchTerm.toLowerCase()) ||
        (r.associateEntity && r.associateEntity.toLowerCase().includes(searchTerm.toLowerCase()));

      const matchesType = filterType === 'All' || r.type === filterType;

      let matchesDate = true;
      if (dateRange.start) {
        matchesDate = matchesDate && new Date(r.date) >= new Date(dateRange.start);
      }
      if (dateRange.end) {
        const endDate = new Date(dateRange.end);
        endDate.setHours(23, 59, 59, 999);
        matchesDate = matchesDate && new Date(r.date) <= endDate;
      }

      return matchesSearch && matchesType && matchesDate;
    });
  }, [records, searchTerm, filterType, dateRange]);

  // --- Pagination Logic ---
  const totalPages = Math.ceil(filteredRecords.length / itemsPerPage);
  const paginatedRecords = filteredRecords.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  // Generate page numbers with ellipsis
  const getPageNumbers = () => {
    const pages = [];
    const maxVisiblePages = 5;

    if (totalPages <= maxVisiblePages) {
      for (let i = 1; i <= totalPages; i++) pages.push(i);
    } else {
      if (currentPage <= 3) {
        pages.push(1, 2, 3, 4, '...', totalPages);
      } else if (currentPage >= totalPages - 2) {
        pages.push(1, '...', totalPages - 3, totalPages - 2, totalPages - 1, totalPages);
      } else {
        pages.push(1, '...', currentPage - 1, currentPage, currentPage + 1, '...', totalPages);
      }
    }
    return pages;
  };

  const handleViewDetails = (record: SystemRecord) => {
    setSelectedRecord(record);
    setIsModalOpen(true);
  };

  const handleExportExcel = () => {
    const headers = ['ID', 'Type', 'Date', 'Reference', 'Primary Entity', 'Associate', 'Status', 'Value'];
    const rows = filteredRecords.map(r => [
      r.id,
      r.type,
      new Date(r.date).toLocaleDateString(),
      r.reference,
      r.primaryEntity,
      r.associateEntity || '',
      r.status,
      r.value || 0
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + [headers.join(','), ...rows.map(e => e.join(','))].join('\n');

    const link = document.createElement("a");
    link.setAttribute("href", encodeURI(csvContent));
    link.setAttribute("download", `system_records_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    setShowExportMenu(false);
  };

  const handleExportPDF = () => {
    window.print();
    setShowExportMenu(false);
  };

  const getTypeColor = (type: string) => {
    switch (type) {
      case 'Patient': return 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300';
      case 'Appointment': return 'bg-violet-100 text-violet-700 dark:bg-violet-900/30 dark:text-violet-300';
      case 'Bill': return 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-300';
      case 'Admission': return 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-300';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  const getTypeIcon = (type: string) => {
    switch (type) {
      case 'Patient': return Users;
      case 'Appointment': return Calendar;
      case 'Bill': return DollarSign;
      case 'Admission': return Bed;
      default: return FileText;
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
            <Database className="text-primary-600" /> {t('records_title')}
          </h1>
          <p className="text-sm text-slate-500 dark:text-slate-400">{t('records_subtitle')}</p>
        </div>

        {/* Export Dropdown */}
        <div className="relative" ref={exportMenuRef}>
          <Button variant="outline" icon={Download} onClick={() => setShowExportMenu(!showExportMenu)}>
            {t('records_export_button')} <ChevronDown size={14} className={`ml-2 transition-transform ${showExportMenu ? 'rotate-180' : ''}`} />
          </Button>
          {showExportMenu && (
            <div className="absolute right-0 mt-2 w-48 bg-white dark:bg-slate-800 rounded-xl shadow-lg border border-slate-200 dark:border-slate-700 z-50 overflow-hidden animate-in fade-in zoom-in-95 duration-100">
              <button 
                onClick={handleExportPDF}
                className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-700 text-left transition-colors"
              >
                <Printer size={16} className="text-slate-400" />
                <span>Export to PDF</span>
              </button>
              <button 
                onClick={handleExportExcel}
                className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-700 text-left transition-colors border-t border-slate-100 dark:border-slate-700"
              >
                <FileSpreadsheet size={16} className="text-green-600" />
                <span>Export to Excel</span>
              </button>
            </div>
          )}
        </div>
      </div>

      <Card className="!p-0 border border-slate-200 dark:border-slate-700 shadow-sm overflow-visible z-10">

        {/* Filters Toolbar */}
        <div className="p-4 border-b border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900 rounded-t-xl grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="relative md:col-span-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
            <input 
              type="text" 
              placeholder={t('records_search_placeholder')} 
              className="pl-9 pr-4 py-2 w-full rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500 outline-none"
              value={searchTerm}
              onChange={e => { setSearchTerm(e.target.value); setCurrentPage(1); }}
            />
          </div>

          <div className="relative">
             <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4 pointer-events-none" />
             <select 
               className="pl-9 pr-4 py-2 w-full rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500 outline-none appearance-none"
               value={filterType}
               onChange={e => { setFilterType(e.target.value); setCurrentPage(1); }}
             >
               <option value="All">{t('records_filter_all')}</option>
               <option value="Patient">{t('records_filter_patients')}</option>
               <option value="Appointment">{t('records_filter_appointments')}</option>
               <option value="Bill">{t('records_filter_invoices')}</option>
               <option value="Admission">{t('records_filter_admissions')}</option>
             </select>
          </div>

          <div className="grid grid-cols-2 gap-4 md:col-span-2">
             <div className="flex items-center gap-2">
               <span className="text-xs font-bold text-slate-500 uppercase">From</span>
               <input 
                 type="date" 
                 className="flex-1 px-3 py-2 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500 outline-none text-slate-600 dark:text-slate-300"
                 value={dateRange.start}
                 onChange={e => { setDateRange({ ...dateRange, start: e.target.value }); setCurrentPage(1); }}
               />
             </div>
             <div className="flex items-center gap-2">
               <span className="text-xs font-bold text-slate-500 uppercase">To</span>
               <input 
                 type="date" 
                 className="flex-1 px-3 py-2 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500 outline-none text-slate-600 dark:text-slate-300"
                 value={dateRange.end}
                 onChange={e => { setDateRange({ ...dateRange, end: e.target.value }); setCurrentPage(1); }}
               />
             </div>
          </div>
        </div>

        {/* Data Table */}
        <div className="overflow-x-auto min-h-[400px]">
          <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
            <thead className="bg-white dark:bg-slate-900">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">{t('records_table_header_ref')}</th>
                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">{t('records_table_header_date')}</th>
                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">{t('records_table_header_primary')}</th>
                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">{t('records_table_header_details')}</th>
                <th className="px-6 py-3 text-center text-xs font-bold text-slate-500 uppercase tracking-wider">{t('records_table_header_status')}</th>
                <th className="px-6 py-3 text-right text-xs font-bold text-slate-500 uppercase tracking-wider">{t('records_table_header_action')}</th>
              </tr>
            </thead>
            <tbody className="bg-white dark:bg-slate-800 divide-y divide-slate-200 dark:divide-slate-700">
              {loading ? (
                <tr><td colSpan={6} className="text-center py-20 text-slate-500">{t('records_table_loading')}</td></tr>
              ) : paginatedRecords.length === 0 ? (
                <tr><td colSpan={6} className="text-center py-20 text-slate-500">{t('records_table_empty')}</td></tr>
              ) : (
                paginatedRecords.map((r) => {
                  const Icon = getTypeIcon(r.type);
                  return (
                    <tr key={r.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/30 transition-colors group">
                      <td className="px-6 py-4 whitespace-nowrap">
                        <div className="flex items-center">
                          <div className={`p-2 rounded-lg mr-3 ${getTypeColor(r.type)}`}>
                            <Icon size={16} />
                          </div>
                          <div>
                            <div className="text-sm font-bold text-slate-900 dark:text-white">{r.reference}</div>
                            <div className="text-xs text-slate-500">{r.type}</div>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600 dark:text-slate-300">
                        {new Date(r.date).toLocaleDateString()} <span className="text-slate-400 text-xs">{new Date(r.date).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <div className="text-sm font-medium text-slate-900 dark:text-white">{r.primaryEntity}</div>
                        {r.associateEntity && <div className="text-xs text-slate-500">w/ {r.associateEntity}</div>}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600 dark:text-slate-300">
                        {r.value ? <span className="font-mono font-bold">${r.value.toLocaleString()}</span> : '-'}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-center">
                        <Badge color={r.status === 'completed' || r.status === 'paid' || r.status === 'active' ? 'green' : 'yellow'}>
                          {r.status}
                        </Badge>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-right">
                        <Button 
                          size="sm"
                          variant="ghost"
                          onClick={() => handleViewDetails(r)}
                          icon={Eye}
                        >
                          View
                        </Button>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>

        {/* Enhanced Pagination Footer */}
        {!loading && filteredRecords.length > 0 && (
           <div className="px-6 py-4 border-t border-slate-200 dark:border-slate-700 flex flex-col sm:flex-row justify-between items-center bg-slate-50 dark:bg-slate-900 rounded-b-xl gap-4">
             <div className="flex items-center gap-4 text-sm text-slate-500 dark:text-slate-400">
                <span>
                  {t('patients_pagination_showing')} <span className="font-medium text-slate-900 dark:text-white">{(currentPage - 1) * itemsPerPage + 1}</span> - <span className="font-medium text-slate-900 dark:text-white">{Math.min(currentPage * itemsPerPage, filteredRecords.length)}</span> {t('patients_pagination_of')} <span className="font-medium text-slate-900 dark:text-white">{filteredRecords.length}</span>
                </span>

                <div className="flex items-center gap-2 border-l border-slate-200 dark:border-slate-700 pl-4">
                  <span>{t('patients_pagination_rows')}</span>
                  <select 
                    className="bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded px-2 py-1 outline-none focus:ring-1 focus:ring-primary-500"
                    value={itemsPerPage}
                    onChange={(e) => { setItemsPerPage(Number(e.target.value)); setCurrentPage(1); }}
                  >
                    <option value={10}>10</option>
                    <option value={15}>15</option>
                    <option value={20}>20</option>
                    <option value={25}>25</option>
                    <option value={50}>50</option>
                  </select>
                </div>
             </div>

             <div className="flex gap-1.5">
               <button 
                 onClick={() => setCurrentPage(1)}
                 disabled={currentPage === 1}
                 className="p-2 rounded-lg border border-slate-200 dark:border-slate-700 hover:bg-white dark:hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
               >
                 <ChevronsLeft size={16} />
               </button>
               <button 
                 onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                 disabled={currentPage === 1}
                 className="p-2 rounded-lg border border-slate-200 dark:border-slate-700 hover:bg-white dark:hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
               >
                 <ChevronLeft size={16} />
               </button>

               {getPageNumbers().map((p, i) => (
                 <button
                   key={i}
                   onClick={() => typeof p === 'number' && setCurrentPage(p)}
                   disabled={typeof p !== 'number'}
                   className={`w-9 h-9 flex items-center justify-center rounded-lg text-sm font-medium transition-all ${
                     p === currentPage 
                       ? 'bg-primary-600 text-white shadow-md shadow-primary-500/30' 
                       : typeof p === 'number' 
                         ? 'border border-slate-200 dark:border-slate-700 hover:bg-white dark:hover:bg-slate-800 text-slate-600 dark:text-slate-300' 
                         : 'text-slate-400 cursor-default'
                   }`}
                 >
                   {p}
                 </button>
               ))}

               <button 
                 onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                 disabled={currentPage === totalPages}
                 className="p-2 rounded-lg border border-slate-200 dark:border-slate-700 hover:bg-white dark:hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
               >
                 <ChevronRight size={16} />
               </button>
               <button 
                 onClick={() => setCurrentPage(totalPages)}
                 disabled={currentPage === totalPages}
                 className="p-2 rounded-lg border border-slate-200 dark:border-slate-700 hover:bg-white dark:hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
               >
                 <ChevronsRight size={16} />
               </button>
             </div>
           </div>
        )}
      </Card>

      {/* Detail Modal */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={t('records_modal_title', {type: selectedRecord?.type || ''})}>
        {selectedRecord && (
          <div className="space-y-6">
            <div className="flex items-center gap-4 p-4 bg-slate-50 dark:bg-slate-900/50 rounded-xl border border-slate-200 dark:border-slate-700">
               <div className={`p-3 rounded-full ${getTypeColor(selectedRecord.type)}`}>
                 {React.createElement(getTypeIcon(selectedRecord.type), { size: 24 })}
               </div>
               <div>
                 <h3 className="text-lg font-bold text-slate-900 dark:text-white">{selectedRecord.reference}</h3>
                 <p className="text-sm text-slate-500">{new Date(selectedRecord.date).toLocaleString()}</p>
               </div>
               <div className="ml-auto">
                 <Badge color="blue">{selectedRecord.status}</Badge>
               </div>
            </div>

            <div className="grid grid-cols-2 gap-4 text-sm">
               <div className="p-3 bg-white dark:bg-slate-800 rounded-lg border border-slate-100 dark:border-slate-700">
                 <span className="block text-xs text-slate-400 uppercase font-bold mb-1">{t('records_modal_primary')}</span>
                 <span className="font-medium text-slate-900 dark:text-white">{selectedRecord.primaryEntity}</span>
               </div>
               {selectedRecord.associateEntity && (
                 <div className="p-3 bg-white dark:bg-slate-800 rounded-lg border border-slate-100 dark:border-slate-700">
                   <span className="block text-xs text-slate-400 uppercase font-bold mb-1">{t('records_modal_associate')}</span>
                   <span className="font-medium text-slate-900 dark:text-white">{selectedRecord.associateEntity}</span>
                 </div>
               )}
               {selectedRecord.value !== undefined && (
                 <div className="p-3 bg-white dark:bg-slate-800 rounded-lg border border-slate-100 dark:border-slate-700">
                   <span className="block text-xs text-slate-400 uppercase font-bold mb-1">{t('records_modal_value')}</span>
                   <span className="font-bold text-emerald-600">${selectedRecord.value.toLocaleString()}</span>
                 </div>
               )}
            </div>

            <div>
              <h4 className="font-bold text-slate-800 dark:text-white mb-2 text-sm">{t('records_modal_raw')}</h4>
              <div className="bg-slate-900 text-slate-300 p-4 rounded-xl text-xs font-mono overflow-auto max-h-60 custom-scrollbar">
                <pre>{JSON.stringify(selectedRecord.details, null, 2)}</pre>
              </div>
            </div>

            <div className="flex justify-end pt-4 border-t dark:border-slate-700">
              <Button onClick={() => setIsModalOpen(false)}>{t('close')}</Button>
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Card, Button, Select, Input } from '../components/UI';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  AreaChart, Area, PieChart, Pie, Cell, Legend, LineChart, Line
} from 'recharts';
import { 
  TrendingUp, Users, Calendar, DollarSign, Download, 
  Activity, PieChart as PieChartIcon, ArrowUpRight, ArrowDownRight, Filter, CheckCircle,
  FilePlus, ClipboardList, Briefcase, Clock, CreditCard, Shield
} from 'lucide-react';
import { api } from '../services/api';
import { useTranslation } from '../context/TranslationContext';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#6366f1'];

export const Reports = () => {
  const [activeTab, setActiveTab] = useState<'financial' | 'operational' | 'demographics' | 'records'>('financial');

  // Date State
  const [rangeType, setRangeType] = useState('30'); // '7', '30', '90', '180', '365', 'custom'
  const [customRange, setCustomRange] = useState({ start: '', end: '' });

  const [loading, setLoading] = useState(true);
  const { t } = useTranslation();

  // Raw Data
  const [bills, setBills] = useState<any[]>([]);
  const [appointments, setAppointments] = useState<any[]>([]);
  const [patients, setPatients] = useState<any[]>([]);
  const [transactions, setTransactions] = useState<any[]>([]);
  const [staff, setStaff] = useState<any[]>([]);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const [b, a, p, t, s] = await Promise.all([
          api.getBills(),
          api.getAppointments(),
          api.getPatients(),
          api.getTransactions(),
          api.getStaff()
        ]);
        setBills(Array.isArray(b) ? b : []);
        setAppointments(Array.isArray(a) ? a : []);
        setPatients(Array.isArray(p) ? p : []);
        setTransactions(Array.isArray(t) ? t : []);
        setStaff(Array.isArray(s) ? s : []);
      } catch (e) {
        console.error("Failed to load report data", e);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  // --- Date Logic ---
  const dateRange = useMemo(() => {
    const end = new Date(); // Today
    const start = new Date();

    if (rangeType === 'custom') {
        return {
            start: customRange.start ? new Date(customRange.start) : new Date(0), // Default to epoch if empty
            end: customRange.end ? new Date(customRange.end) : end
        };
    }

    const days = parseInt(rangeType);
    start.setDate(end.getDate() - days);
    // Reset hours for accurate comparison
    start.setHours(0,0,0,0);
    end.setHours(23,59,59,999);

    return { start, end };
  }, [rangeType, customRange]);

  const filterByDate = (data: any[], dateField: string) => {
    return data.filter(item => {
        if (!item[dateField]) return false;
        const d = new Date(item[dateField]);
        return d >= dateRange.start && d <= dateRange.end;
    });
  };

  // --- Aggregation Logic ---

  const financialStats = useMemo(() => {
    const filteredBills = filterByDate(bills, 'date');
    const filteredTrans = filterByDate(transactions, 'date');

    const totalRevenue = filteredBills.reduce((sum, b) => sum + (b.paidAmount || 0), 0);
    const totalBilled = filteredBills.reduce((sum, b) => sum + (b.totalAmount || 0), 0);
    const pendingAmount = Math.max(0, totalBilled - totalRevenue);
    const totalInvoices = filteredBills.length;

    // Revenue Trend (Daily)
    const trendMap = new Map();
    // Fill in dates for the range (up to 30 points to avoid clutter, or aggregate if large range)
    const daySpan = Math.ceil((dateRange.end.getTime() - dateRange.start.getTime()) / (1000 * 3600 * 24));
    const isLargeRange = daySpan > 60;

    filteredBills.forEach(b => {
      const d = new Date(b.date);
      // Group by Month if range > 60 days, else Day
      const key = isLargeRange 
        ? d.toLocaleDateString('en-US', { month: 'short', year: '2-digit' })
        : d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });

      trendMap.set(key, (trendMap.get(key) || 0) + (b.paidAmount || 0));
    });

    // Convert map to array and sort by date would be ideal, but for now relies on map insertion order roughly or sort keys
    const revenueTrend = Array.from(trendMap).map(([name, value]) => ({ name, value }));

    // Status Distribution
    const statusCounts = filteredBills.reduce((acc: any, b) => {
      acc[b.status] = (acc[b.status] || 0) + 1;
      return acc;
    }, {});
    const statusDist = Object.keys(statusCounts).map(key => ({ name: key, value: statusCounts[key] }));

    // Payment Methods Breakdown (from Transactions)
    const methodCounts = filteredTrans.filter((t: any) => t.type === 'income').reduce((acc: any, t: any) => {
        const m = t.method || 'Unknown';
        acc[m] = (acc[m] || 0) + t.amount;
        return acc;
    }, {});
    const methodDist = Object.keys(methodCounts).map(key => ({ name: key, value: methodCounts[key] }));

    // Top Services (from Bill Items)
    // We need to parse bill items. Since bills state already has items attached from controller:
    const serviceCounts: Record<string, number> = {};
    filteredBills.forEach(b => {
        b.items?.forEach((item: any) => {
            // Simple grouping by first 2 words to aggregate similar services
            const name = item.description.split(':').pop()?.trim() || item.description;
            serviceCounts[name] = (serviceCounts[name] || 0) + item.amount;
        });
    });
    const topServices = Object.entries(serviceCounts)
        .map(([name, value]) => ({ name, value }))
        .sort((a,b) => b.value - a.value)
        .slice(0, 5);

    return { totalRevenue, pendingAmount, totalInvoices, revenueTrend, statusDist, methodDist, topServices };
  }, [bills, transactions, dateRange]);

  const operationalStats = useMemo(() => {
    const filteredAppts = filterByDate(appointments, 'datetime');
    const totalAppts = filteredAppts.length;
    const completedAppts = filteredAppts.filter(a => a && a.status === 'completed').length;

    // Appointments by Doctor
    const doctorCounts = filteredAppts.reduce((acc: any, a) => {
      if(a && a.staffName) {
        acc[a.staffName] = (acc[a.staffName] || 0) + 1;
      }
      return acc;
    }, {});
    const doctorPerformance = Object.keys(doctorCounts)
      .map(key => ({ name: key.split(' ')[1] || key, value: doctorCounts[key] })) 
      .sort((a, b) => b.value - a.value)
      .slice(0, 8);

    // Department Workload
    const deptCounts: Record<string, number> = {};
    filteredAppts.forEach(a => {
        // Find staff to get dept
        const doc = staff.find(s => s.id === a.staffId);
        const dept = doc?.department || 'General';
        deptCounts[dept] = (deptCounts[dept] || 0) + 1;
    });
    const deptData = Object.entries(deptCounts).map(([name, value]) => ({ name, value })).sort((a,b) => b.value - a.value);

    // Peak Hours
    const hourCounts = Array(24).fill(0);
    filteredAppts.forEach(a => {
        const h = new Date(a.datetime).getHours();
        hourCounts[h]++;
    });
    // Filter to working hours (e.g., 7am to 8pm) to remove empty night slots
    const peakHoursData = hourCounts.map((count, hour) => ({
        name: `${hour}:00`,
        value: count
    })).filter((d, i) => i >= 7 && i <= 20);

    return { totalAppts, completedAppts, doctorPerformance, deptData, peakHoursData };
  }, [appointments, staff, dateRange]);

  const demographicStats = useMemo(() => {
    // Patients created in range (for registration stats)
    // BUT for demographics usually we look at ALL patients or Active patients in range.
    // Let's filter by creation date for "New Registrations" but use ALL for demographics snapshot?
    // User requested "enrich tabs", so usually Demographics reflects the current patient base or those active in period.
    // Let's use Patients Active in Period (Visits or Created)

    // Find patient IDs active in this period
    const activePatientIds = new Set([
        ...filterByDate(appointments, 'datetime').map(a => a.patientId),
        ...filterByDate(patients, 'createdAt').map(p => p.id)
    ]);

    const activePatients = patients.filter(p => activePatientIds.has(p.id));
    const totalPatients = activePatients.length;

    // Gender
    const genderCounts = activePatients.reduce((acc: any, p) => {
      const g = p.gender ? p.gender.charAt(0).toUpperCase() + p.gender.slice(1) : 'Unknown';
      acc[g] = (acc[g] || 0) + 1;
      return acc;
    }, {});
    const genderDist = Object.keys(genderCounts).map(key => ({ name: key, value: genderCounts[key] }));

    // Age Groups
    const ageGroups = { '0-12': 0, '13-18': 0, '19-35': 0, '36-60': 0, '60+': 0 };
    activePatients.forEach(p => {
      if (p.age <= 12) ageGroups['0-12']++;
      else if (p.age <= 18) ageGroups['13-18']++;
      else if (p.age <= 35) ageGroups['19-35']++;
      else if (p.age <= 60) ageGroups['36-60']++;
      else ageGroups['60+']++;
    });
    const ageDist = Object.keys(ageGroups).map(key => ({ name: key, value: ageGroups[key as keyof typeof ageGroups] }));

    // Insurance Distribution
    const insuranceCounts = activePatients.reduce((acc: any, p) => {
        if (p.hasInsurance && p.insuranceDetails?.provider) {
            acc[p.insuranceDetails.provider] = (acc[p.insuranceDetails.provider] || 0) + 1;
        } else {
            acc['Self Pay'] = (acc['Self Pay'] || 0) + 1;
        }
        return acc;
    }, {});
    const insuranceDist = Object.entries(insuranceCounts)
        .map(([name, value]) => ({ name, value: value as number }))
        .sort((a,b) => b.value - a.value);

    return { totalPatients, genderDist, ageDist, insuranceDist };
  }, [patients, appointments, dateRange]);

  const recordsStats = useMemo(() => {
    const filteredPatients = filterByDate(patients, 'createdAt');
    const filteredAppts = filterByDate(appointments, 'datetime');
    const filteredBills = filterByDate(bills, 'date');

    // Recent Activity Feed
    const activity = [
        ...filteredPatients.map(p => ({ 
            type: 'Patient', 
            text: t('report_activity_patient_new', {name: p.fullName}), 
            subtext: `ID: ${p.patientId}`,
            date: p.createdAt, 
            id: `p-${p.id}`, 
            icon: Users, 
            color: 'text-blue-600 bg-blue-50 dark:bg-blue-900/20 dark:text-blue-400' 
        })),
        ...filteredAppts.map(a => ({ 
            type: 'Appointment', 
            text: t('report_activity_appt_new', {patient: a.patientName}), 
            subtext: `Dr. ${a.staffName} (${a.type})`,
            date: a.datetime, 
            id: `a-${a.id}`, 
            icon: Calendar, 
            color: 'text-violet-600 bg-violet-50 dark:bg-violet-900/20 dark:text-violet-400' 
        })),
        ...filteredBills.map(b => ({ 
            type: 'Bill', 
            text: t('report_activity_bill_new', {number: b.billNumber}), 
            subtext: `$${b.totalAmount.toLocaleString()} (${b.status})`,
            date: b.date, 
            id: `b-${b.id}`, 
            icon: DollarSign, 
            color: 'text-emerald-600 bg-emerald-50 dark:bg-emerald-900/20 dark:text-emerald-400' 
        }))
    ].sort((a: any, b: any) => new Date(b.date).getTime() - new Date(a.date).getTime()).slice(0, 50);

    return {
        counts: {
            patients: filteredPatients.length,
            appointments: filteredAppts.length,
            bills: filteredBills.length
        },
        activity
    };
  }, [patients, appointments, bills, dateRange, t]);

  const handleExport = () => {
    const headers = ['Report', 'Start Date', 'End Date', 'Total Revenue', 'Total Patients'];
    const row = [activeTab, dateRange.start.toLocaleDateString(), dateRange.end.toLocaleDateString(), financialStats.totalRevenue, demographicStats.totalPatients];
    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(','), row.join(',')].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `allcare_report_${activeTab}_${Date.now()}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  if (loading) return <div className="flex justify-center items-center h-96 text-slate-400">{t('loading')}</div>;

  const StatCard = ({ title, value, icon: Icon, color, subtext }: any) => (
    <div className="bg-white dark:bg-slate-800 p-5 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm flex items-start justify-between hover:shadow-md transition-shadow">
      <div>
        <p className="text-slate-500 dark:text-slate-400 text-xs font-bold uppercase tracking-wider mb-1">{title}</p>
        <h3 className="text-2xl font-bold text-slate-900 dark:text-white">{value}</h3>
        {subtext && <p className="text-xs text-slate-400 mt-1 flex items-center gap-1">{subtext}</p>}
      </div>
      <div className={`p-3 rounded-lg ${color}`}>
        <Icon size={24} />
      </div>
    </div>
  );

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">{t('reports_title')}</h1>
          <p className="text-sm text-slate-500 dark:text-slate-400">{t('reports_subtitle')}</p>
        </div>

        <div className="flex flex-wrap gap-2 items-center">
          <div className="relative">
             <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
             <select 
               className="pl-9 pr-4 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg text-sm font-medium focus:ring-2 focus:ring-primary-500 outline-none appearance-none text-slate-700 dark:text-slate-200"
               value={rangeType}
               onChange={e => setRangeType(e.target.value)}
             >
               <option value="7">Last 7 Days (Week)</option>
               <option value="30">Last 30 Days (Month)</option>
               <option value="90">Last 3 Months</option>
               <option value="180">Last 6 Months</option>
               <option value="365">Last Year</option>
               <option value="custom">Custom Range</option>
             </select>
          </div>

          {rangeType === 'custom' && (
              <div className="flex items-center gap-2 animate-in fade-in slide-in-from-left-2">
                  <Input 
                    type="date" 
                    value={customRange.start} 
                    onChange={e => setCustomRange({...customRange, start: e.target.value})} 
                    className="!py-2 !text-sm w-36"
                  />
                  <span className="text-slate-400">-</span>
                  <Input 
                    type="date" 
                    value={customRange.end} 
                    onChange={e => setCustomRange({...customRange, end: e.target.value})} 
                    className="!py-2 !text-sm w-36"
                  />
              </div>
          )}

          <Button variant="outline" icon={Download} onClick={handleExport}>{t('reports_export_button')}</Button>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-gray-200 dark:border-slate-700 bg-white dark:bg-slate-800 rounded-t-xl px-4 pt-2 overflow-x-auto">
        {[
          { id: 'financial', label: t('reports_tab_financial'), icon: DollarSign },
          { id: 'operational', label: t('reports_tab_operational'), icon: Activity },
          { id: 'demographics', label: t('reports_tab_demographics'), icon: Users },
          { id: 'records', label: t('reports_tab_records'), icon: FilePlus },
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)} 
            className={`px-6 py-3 font-medium text-sm border-b-2 transition-all flex items-center gap-2 whitespace-nowrap 
              ${activeTab === tab.id 
                ? 'border-primary-600 text-primary-600 bg-primary-50/50 dark:bg-primary-900/20' 
                : 'border-transparent text-gray-500 dark:text-slate-400 hover:text-gray-700 dark:hover:text-slate-200 hover:bg-gray-50 dark:hover:bg-slate-700'}`}
          >
            <tab.icon size={16} /> {tab.label}
          </button>
        ))}
      </div>

      <div className="bg-white dark:bg-slate-800 rounded-b-xl shadow-sm border border-t-0 border-gray-200 dark:border-slate-700 p-6 min-h-[500px]">

        {/* FINANCIAL REPORT */}
        {activeTab === 'financial' && (
          <div className="space-y-8 animate-in fade-in">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <StatCard 
                title={t('reports_card_revenue')} 
                value={`$${financialStats.totalRevenue.toLocaleString()}`} 
                icon={DollarSign} 
                color="bg-emerald-100 text-emerald-600 dark:bg-emerald-900/30 dark:text-emerald-400"
                subtext={<span className="text-emerald-600 font-bold flex items-center gap-1"><ArrowUpRight size={12}/> Collected</span>}
              />
              <StatCard 
                title={t('reports_card_outstanding')} 
                value={`$${financialStats.pendingAmount.toLocaleString()}`} 
                icon={TrendingUp} 
                color="bg-orange-100 text-orange-600 dark:bg-orange-900/30 dark:text-orange-400"
                subtext={<span className="text-slate-400">Across {financialStats.totalInvoices} invoices</span>}
              />
              <StatCard 
                title={t('reports_card_avg_invoice')}
                value={`$${Math.round(financialStats.totalRevenue / (financialStats.totalInvoices || 1)).toLocaleString()}`} 
                icon={PieChartIcon} 
                color="bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400"
                subtext={<span className="text-slate-400">Per patient visit</span>}
              />
            </div>

            {/* Charts Row 1: Trend & Distribution */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 space-y-4">
                <h3 className="font-bold text-slate-800 dark:text-white flex items-center gap-2"><Activity size={18} className="text-primary-500"/> {t('reports_chart_revenue_trend')}</h3>
                <div className="h-80 w-full bg-slate-50 dark:bg-slate-900/50 rounded-xl p-4 border border-slate-100 dark:border-slate-700">
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={financialStats.revenueTrend}>
                      <defs>
                        <linearGradient id="colorRev" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#10b981" stopOpacity={0.2}/>
                          <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                        </linearGradient>
                      </defs>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" className="dark:stroke-slate-700" />
                      <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} dy={10} minTickGap={30} />
                      <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                      <Tooltip contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)', backgroundColor: '#fff', color: '#1e293b' }} />
                      <Area type="monotone" dataKey="value" stroke="#10b981" strokeWidth={3} fillOpacity={1} fill="url(#colorRev)" />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
              </div>

              <div className="space-y-4">
                <h3 className="font-bold text-slate-800 dark:text-white flex items-center gap-2"><CreditCard size={18} className="text-primary-500"/> Income by Method</h3>
