        {/* NEW RECORDS REPORT */}
        {activeTab === 'records' && (
          <div className="space-y-8 animate-in fade-in">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <StatCard 
                title={t('reports_card_new_patients')} 
                value={recordsStats.counts.patients} 
                icon={Users} 
