                          <td className="px-4 py-3 text-sm text-right font-mono text-slate-500">
                            {item.cost !== undefined && `$${item.cost}`}
                            {item.base_cost !== undefined && `$${item.base_cost}`}
                            {item.rate !== undefined && `${item.rate}%`}
